91	------------------------------------------------------------------------------
92	-- Package Body
93	------------------------------------------------------------------------------
94	package body psi_tb_activity_pkg is
95	
96		-- *** CheckNoActivity ***
97		procedure CheckNoActivity(signal Sig : in std_logic;
98		                          IdleTime   : in time;
99		                          Level      : in integer range -1 to 1; -- -1 = don't check, 0 = low, 1 = high
100		                          Msg        : in string := "";
101		                          Prefix     : in string := "###ERROR###: ") is
102		begin
103			wait for IdleTime;
104			assert Sig'last_event >= IdleTime
105			report Prefix & Msg & "[Unexpected Activity]"
106			severity error;
107			if Level /= -1 then
108				StdlCompare(Level, Sig, "CheckNoActivity: " & Msg, Prefix);
109			end if;
110		end procedure;
111	
112		-- *** CheckNoActivityStlv ***
113		procedure CheckNoActivityStlv(signal Sig : in std_logic_vector;
114		                              IdleTime   : in time;
115		                              Level      : in integer range -1 to integer'high; -- -1 = don't check, otherwise interpreted unsigned
116		                              Msg        : in string := "";
117		                              Prefix     : in string := "###ERROR###: ") is
118		begin
119			wait for IdleTime;
120			assert Sig'last_event >= IdleTime
121			report Prefix & Msg & "[Unexpected Activity]"
122			severity error;
123			if Level /= -1 then
124				StdlvCompareInt(Level, Sig, "CheckNoActivityStlv: " & Msg, false, 0, Prefix);
125			end if;
126		end procedure;
127	
128		-- *** CheckLastActivity ***
129		procedure CheckLastActivity(signal Sig : in std_logic;
130		                            IdleTime   : in time;
